6	#include <postgres.h>
7	#include <access/htup.h>
8	#include <access/htup_details.h>
9	#include <access/tableam.h>
10	#include <access/xact.h>
11	#include <nodes/memnodes.h>
12	#include <storage/lmgr.h>
13	#include <storage/lockdefs.h>
14	#include <utils/builtins.h>
15	#include <utils/memutils.h>
16	#include <utils/snapmgr.h>
17	
18	#include <compat/compat.h>
19	#include "ts_catalog/catalog.h"
20	#include <scan_iterator.h>
21	#include <scanner.h>
22	#include <time_bucket.h>
23	#include <time_utils.h>
24	
25	#include "continuous_aggs/materialize.h"
26	#include "debug_point.h"
27	#include "invalidation_threshold.h"
28	#include "ts_catalog/continuous_agg.h"
29	
30	/*
31	 * Invalidation threshold.
32	 *
33	 * The invalidation threshold acts as a dampener on a hypertable to make sure
34	 * that invalidations written during inserts won't cause too much write
35	 * amplification in "hot" regions---typically the "head" of the table. The
36	 * presumption is that most inserts happen at recent time intervals, and those
37	 * intervals will be invalid until writes move out of them. Therefore, it
38	 * isn't worth writing invalidations in that region since it is presumed
39	 * out-of-date anyway. Further, although it is possible to refresh a
40	 * continuous aggregate in those "hot" regions, it will lead to partially
41	 * filled buckets. Thus, refreshing those intervals is discouraged since the
42	 * aggregate will be immediately out-of-date until the buckets are filled. The
43	 * invalidation threshold is, in other words, used as a marker that lags
44	 * behind the head of the hypertable, where invalidations are written before
45	 * the threshold but not after it.
46	 *
47	 * The invalidation threshold is moved forward (and only forward) by refreshes
48	 * on continuous aggregates when it covers a window that stretches beyond the
49	 * current threshold. The invalidation threshold needs to be moved in its own
50	 * transaction, with exclusive access, before the refresh starts to
51	 * materialize data. This is to avoid losing any invalidations that occur
52	 * between the start of the transaction that moves the threshold and its end
53	 * (when the new threshold becomes visible).
54	 *
55	 * ______________________________________________
56	 * |_______________________________________|_____| recent data
57	 *                                        ^
58	 *      invalidations written here        |  no invalidations
59	 *                                        |
60	 *                               invalidation threshold
61	 *
62	 * Transactions that use an isolation level stronger than READ COMMITTED will
63	 * not be able to "see" changes to the invalidation threshold that may have
64	 * been made while they were running. Therefore, they always create records
65	 * in the hypertable invalidation log. See the cache_inval_entry_write()
66	 * implementation in tsl/src/continuous_aggs/insert.c
67	 */
68	
69	typedef struct InvalidationThresholdData
70	{
71		const ContinuousAgg *cagg;
72		const InternalTimeRange *refresh_window;
73		int64 computed_invalidation_threshold;
74	} InvalidationThresholdData;
75	
76	typedef struct InvalidationThresholdGetData
77	{
78		int32 hypertable_id;
79		int64 threshold;
80	} InvalidationThresholdGetData;
81	
82	static ScanTupleResult
83	invalidation_threshold_scan_get(TupleInfo *ti, void *const data)
84	{
85		InvalidationThresholdGetData *the_data = (InvalidationThresholdGetData *) data;
86		bool isnull;
87		Datum datum;
88	
89		if (ti->lockresult == TM_Updated || ti->lockresult == TM_Deleted)
90			return SCAN_RESTART_WITH_NEW_SNAPSHOT;
91	
92		Ensure(ti->lockresult == TM_Ok,
93			   "unable to lock invalidation threshold tuple for hypertable %d (lock result %d)",
94			   the_data->hypertable_id,
95			   ti->lockresult);
96	
97		datum = slot_getattr(ti->slot, Anum_continuous_aggs_invalidation_threshold_watermark, &isnull);
98	
99		Ensure(!isnull, "invalidation threshold for hypertable %d is null", the_data->hypertable_id);
100		the_data->threshold = DatumGetInt64(datum);
101	
102		return SCAN_DONE;
103	}
104	
105	static ScanTupleResult
106	invalidation_threshold_scan_update(TupleInfo *ti, void *const data)
107	{
108		DEBUG_WAITPOINT("invalidation_threshold_scan_update_enter");
109	
110		InvalidationThresholdData *invthresh = (InvalidationThresholdData *) data;
111	
112		/* If the tuple was modified concurrently, retry the operation and use a new snapshot
113		 * to see the updated tuple. */
114		if (ti->lockresult == TM_Updated)
115			return SCAN_RESTART_WITH_NEW_SNAPSHOT;
116	
117		if (ti->lockresult != TM_Ok)
118		{
119			elog(ERROR,
120				 "unable to lock invalidation threshold tuple for hypertable %d (lock result %d)",
121				 invthresh->cagg->data.raw_hypertable_id,
122				 ti->lockresult);
123	
124			pg_unreachable();
125		}
126	
127		bool isnull;
128		Datum datum =
129			slot_getattr(ti->slot, Anum_continuous_aggs_invalidation_threshold_watermark, &isnull);
130	
131		/* NULL should never happen because we always initialize the threshold with the MIN
132		 * value of the partition type */
133		Ensure(!isnull,
134			   "invalidation threshold for hypertable %d is null",
135			   invthresh->cagg->data.raw_hypertable_id);
136	
137		int64 current_invalidation_threshold = DatumGetInt64(datum);
138	
139		/* Compute new invalidation threshold. Note that this computation caps the
140		 * threshold at the end of the last bucket that holds data in the
141		 * underlying hypertable. */
142		invthresh->computed_invalidation_threshold =
143			invalidation_threshold_compute(invthresh->cagg, invthresh->refresh_window);
144	
145		if (invthresh->computed_invalidation_threshold > current_invalidation_threshold)
146		{
147			bool nulls[Natts_continuous_agg];
148			Datum values[Natts_continuous_agg];
149			bool do_replace[Natts_continuous_agg] = { false };
150			bool should_free;
151			HeapTuple tuple = ts_scanner_fetch_heap_tuple(ti, false, &should_free);
152			HeapTuple new_tuple;
153			TupleDesc tupdesc = ts_scanner_get_tupledesc(ti);
154	
155			heap_deform_tuple(tuple, tupdesc, values, nulls);
156	
157			do_replace[AttrNumberGetAttrOffset(Anum_continuous_aggs_invalidation_threshold_watermark)] =
158				true;
159			values[AttrNumberGetAttrOffset(Anum_continuous_aggs_invalidation_threshold_watermark)] =
160				Int64GetDatum(invthresh->computed_invalidation_threshold);
161	
162			new_tuple = heap_modify_tuple(tuple, tupdesc, values, nulls, do_replace);
163	
164			ts_catalog_update(ti->scanrel, new_tuple);
165			heap_freetuple(new_tuple);
166	
167			if (should_free)
168				heap_freetuple(tuple);
169		}
170		else
171		{
172			elog(DEBUG1,
173				 "hypertable %d existing watermark >= new invalidation threshold " INT64_FORMAT
174				 " " INT64_FORMAT,
175				 invthresh->cagg->data.raw_hypertable_id,
176				 current_invalidation_threshold,
177				 invthresh->computed_invalidation_threshold);
178			invthresh->computed_invalidation_threshold = current_invalidation_threshold;
179		}
180	
181		return SCAN_CONTINUE;
182	}
183	
184	/*
185	 * Get the invalidation threshold for the hypertable.
186	 *
187	 * This will also lock the row.
188	 */
189	int64
190	invalidation_threshold_get(int32 hypertable_id, Oid type)
191	{
192		InvalidationThresholdGetData data = { .hypertable_id = hypertable_id };
193		ScanKeyData scankey[1];
194		Catalog *catalog = ts_catalog_get();
195		ScanTupLock scantuplock = {
196			.waitpolicy = LockWaitBlock,
197			.lockmode = LockTupleExclusive,
198		};
199		PushActiveSnapshot(GetLatestSnapshot());
200		ScannerCtx scanctx = {
201			.table = catalog_get_table_id(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD),
202			.index =
203				catalog_get_index(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD, BGW_JOB_PKEY_IDX),
204			.nkeys = 1,
205			.scankey = scankey,
206			.data = &data,
207			.tuple_found = invalidation_threshold_scan_get,
208			.lockmode = RowShareLock,
209			.scandirection = ForwardScanDirection,
210			.result_mctx = CurrentMemoryContext,
211			.tuplock = &scantuplock,
212			.flags = SCANNER_F_KEEPLOCK,
213			.snapshot = GetActiveSnapshot(),
214		};
215	
216		ScanKeyInit(&scankey[0],
217					Anum_continuous_aggs_invalidation_threshold_hypertable_id,
218					BTEqualStrategyNumber,
219					F_INT4EQ,
220					Int32GetDatum(hypertable_id));
221	
222		bool found = ts_scanner_scan_one(&scanctx, false, CAGG_INVALIDATION_THRESHOLD_NAME);
223		Ensure(found, "invalidation threshold for hypertable %d not found", hypertable_id);
224		PopActiveSnapshot();
225		return data.threshold;
226	}
227	
228	/*
229	 * Set a new invalidation threshold.
230	 *
231	 * The threshold is only updated if the new threshold is greater than the old
232	 * one.
233	 *
234	 * On success, the new threshold is returned, otherwise the existing threshold
235	 * is returned instead.
236	 */
237	int64
238	invalidation_threshold_set_or_get(const ContinuousAgg *cagg,
239									  const InternalTimeRange *refresh_window)
240	{
241		bool found = false;
242		ScanKeyData scankey[1];
243		Catalog *catalog = ts_catalog_get();
244		ScanTupLock scantuplock = {
245			.waitpolicy = LockWaitBlock,
246			.lockmode = LockTupleExclusive,
247		};
248		InvalidationThresholdData updatectx = {
249			.cagg = cagg,
250			.refresh_window = refresh_window,
251		};
252		PushActiveSnapshot(GetLatestSnapshot());
253		ScannerCtx scanctx = {
254			.table = catalog_get_table_id(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD),
255			.index =
256				catalog_get_index(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD, BGW_JOB_PKEY_IDX),
257			.nkeys = 1,
258			.scankey = scankey,
259			.data = &updatectx,
260			.tuple_found = invalidation_threshold_scan_update,
261			.lockmode = RowExclusiveLock,
262			.scandirection = ForwardScanDirection,
263			.result_mctx = CurrentMemoryContext,
264			.tuplock = &scantuplock,
265			.flags = SCANNER_F_KEEPLOCK,
266			/* We update the threshold value using this scanner. Since the scanner uses SnapshotSelf
267			 * per default, the updated tuple would become immediately visible to the scanner (the
268			 * snapshot includes "changes made by the current command") and ts_scanner_scan_one()
269			 * would fail due to the second found tuple. A normal MVCC snapshot is used to prevent
270			 * the update is immediately seen by the scanner. */
271			.snapshot = GetActiveSnapshot(),
272		};
273	
274		ScanKeyInit(&scankey[0],
275					Anum_continuous_aggs_invalidation_threshold_hypertable_id,
276					BTEqualStrategyNumber,
277					F_INT4EQ,
278					Int32GetDatum(cagg->data.raw_hypertable_id));
279	
280		found = ts_scanner_scan_one(&scanctx, false, CAGG_INVALIDATION_THRESHOLD_NAME);
281		Ensure(found,
282			   "invalidation threshold for hypertable %d not found",
283			   cagg->data.raw_hypertable_id);
284		PopActiveSnapshot();
285	
286		return updatectx.computed_invalidation_threshold;
287	}
288	
289	/*
290	 * Compute a new invalidation threshold.
291	 *
292	 * The new invalidation threshold returned is the end of the given refresh
293	 * window, unless it ends at "infinity" in which case the threshold is capped
294	 * at the end of the last bucket materialized.
295	 */
296	int64
297	invalidation_threshold_compute(const ContinuousAgg *cagg, const InternalTimeRange *refresh_window)
298	{
299		bool max_refresh = false;
300		Hypertable *ht = ts_hypertable_get_by_id(cagg->data.raw_hypertable_id);
301	
302		if (IS_TIMESTAMP_TYPE(refresh_window->type))
303			max_refresh = TS_TIME_IS_END(refresh_window->end, refresh_window->type) ||
304						  TS_TIME_IS_NOEND(refresh_window->end, refresh_window->type);
305		else
306			max_refresh = TS_TIME_IS_MAX(refresh_window->end, refresh_window->type);
307	
308		if (max_refresh)
309		{
310			bool isnull;
311			int64 maxval = ts_hypertable_get_open_dim_max_value(ht, 0, &isnull);
312	
313			if (isnull)
314			{
315				/* No data in hypertable */
316				return cagg_get_time_min(cagg);
317			}
318			else
319			{
320				if (cagg->bucket_function->bucket_fixed_interval == false)
321				{
322					return ts_compute_beginning_of_the_next_bucket_variable(maxval,
323																			cagg->bucket_function);
324				}
325	
326				int64 bucket_width = ts_continuous_agg_fixed_bucket_width(cagg->bucket_function);
327				Assert(bucket_width > 0);
328				int64 bucket_start = ts_time_bucket_by_type(bucket_width, maxval, refresh_window->type);
329				/* Add one bucket to get to the end of the last bucket */
330				return ts_time_saturating_add(bucket_start, bucket_width, refresh_window->type);
331			}
332		}
333	
334		return refresh_window->end;
335	}
336	
337	/*
338	 * Initialize the invalidation threshold.
339	 *
340	 * The initial value of the invalidation threshold should be the MIN
341	 * value for the Continuous Aggregate partition type.
342	 */
343	void
344	invalidation_threshold_initialize(const ContinuousAgg *cagg)
345	{
346		bool found = false;
347		ScanKeyData scankey[1];
348		Catalog *catalog = ts_catalog_get();
349		ScannerCtx scanctx = {
350			.table = catalog_get_table_id(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD),
351			.index =
352				catalog_get_index(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD, BGW_JOB_PKEY_IDX),
353			.nkeys = 1,
354			.scankey = scankey,
355			.lockmode = ShareUpdateExclusiveLock,
356			.scandirection = ForwardScanDirection,
357			.result_mctx = CurrentMemoryContext,
358			.flags = SCANNER_F_KEEPLOCK,
359		};
360	
361		ScanKeyInit(&scankey[0],
362					Anum_continuous_aggs_invalidation_threshold_hypertable_id,
363					BTEqualStrategyNumber,
364					F_INT4EQ,
365					Int32GetDatum(cagg->data.raw_hypertable_id));
366	
367		found = ts_scanner_scan_one(&scanctx, false, CAGG_INVALIDATION_THRESHOLD_NAME);
368	
369		if (!found)
370		{
371			Relation rel =
372				table_open(catalog_get_table_id(catalog, CONTINUOUS_AGGS_INVALIDATION_THRESHOLD),
373						   ShareUpdateExclusiveLock);
374			TupleDesc desc = RelationGetDescr(rel);
375			Datum values[Natts_continuous_aggs_invalidation_threshold];
376			bool nulls[Natts_continuous_aggs_invalidation_threshold] = { false };
377			CatalogSecurityContext sec_ctx;
378			/* get the MIN value for the partition type */
379			int64 min_value = cagg_get_time_min(cagg);
380	
381			values[AttrNumberGetAttrOffset(Anum_continuous_aggs_invalidation_threshold_hypertable_id)] =
382				Int32GetDatum(cagg->data.raw_hypertable_id);
383	
384			values[AttrNumberGetAttrOffset(Anum_continuous_aggs_invalidation_threshold_watermark)] =
385				Int64GetDatum(min_value);
386	
387			ts_catalog_database_info_become_owner(ts_catalog_database_info_get(), &sec_ctx);
388			ts_catalog_insert_values(rel, desc, values, nulls);
389			ts_catalog_restore_user(&sec_ctx);
390			table_close(rel, NoLock);
391		}
392	}
393	

