402		DateADT date = PG_GETARG_DATEADT(1);
403		DateADT origin = 0;
404		Timestamp origin_ts = DEFAULT_ORIGIN;
405		Timestamp timestamp, result;
406	
407		if (DATE_NOT_FINITE(date))
408			PG_RETURN_DATEADT(date);
409	
410		/* convert to timestamp (NOT tz), bucket, convert back to date */
411		timestamp = DatumGetTimestamp(DirectFunctionCall1(date_timestamp, PG_GETARG_DATUM(1)));
412		Assert(!TIMESTAMP_NOT_FINITE(timestamp));
413	
414		if (PG_NARGS() > 2)
415		{
416			origin = PG_GETARG_DATEADT(2);
417			if (!interval->month)
418				origin_ts =
419					DatumGetTimestamp(DirectFunctionCall1(date_timestamp, DateADTGetDatum(origin)));
420		}
421	
422		if (interval->month)
423		{
424			validate_month_bucket(interval);
425	
426			date = bucket_month(interval->month, date, origin);
427			PG_RETURN_DATEADT(date);
428		}
429		else
430		{
431			int64 period = get_interval_period_timestamp_units(interval);
432			/* check the period aligns on a date */
433			check_period_is_daily(period);
434	
435			TIME_BUCKET_TS(period, timestamp, result, origin_ts);
436			PG_RETURN_DATUM(DirectFunctionCall1(timestamp_date, TimestampGetDatum(result)));
