442	TSDLLEXPORT Datum
443	ts_date_offset_bucket(PG_FUNCTION_ARGS)
444	{
445		Datum period = PG_GETARG_DATUM(0);
446		Datum date = PG_GETARG_DATUM(1);
447	
448		if (DATE_NOT_FINITE(DatumGetDateADT(date)))
449			PG_RETURN_DATUM(date);
450	
451		/* Apply offset. */
452		Datum time = DirectFunctionCall2(date_mi_interval, date, PG_GETARG_DATUM(2));
453		date = DirectFunctionCall1(timestamp_date, time);
454		date = DirectFunctionCall2(ts_date_bucket, period, date);
455	
456		/* Remove offset. */
457		time = DirectFunctionCall2(date_pl_interval, date, PG_GETARG_DATUM(2));
458		date = DirectFunctionCall1(timestamp_date, time);
459		PG_RETURN_DATUM(date);
460	}
461	
462	TSDLLEXPORT int64
463	ts_time_bucket_by_type(int64 interval, int64 timestamp, Oid timestamp_type)
464	{
465		NullableDatum null_datum = INIT_NULL_DATUM;
466		return ts_time_bucket_by_type_extended(interval,
467											   timestamp,
468											   timestamp_type,
469											   null_datum,
470											   null_datum);
471	}
472	
473	/* when working with time_buckets stored in our catalog, we may not know ahead of time which
474	 * bucketing function to use, this function dynamically dispatches to the correct time_bucket_<foo>
475	 * based on an inputted timestamp_type
476	 */
477	TSDLLEXPORT int64
478	ts_time_bucket_by_type_extended(int64 interval, int64 timestamp, Oid timestamp_type,
479									NullableDatum offset, NullableDatum origin)
480	{
481		/* Defined offset and origin in one function is not supported */
482		Assert(offset.isnull == true || origin.isnull == true);
483	
484		Datum timestamp_in_time_type = ts_internal_to_time_value(timestamp, timestamp_type);
485		Datum interval_in_interval_type;
486		Datum time_bucketed;
487		Datum (*bucket_function)(PG_FUNCTION_ARGS);
488	
489		switch (timestamp_type)
490		{
491			case INT2OID:
492				interval_in_interval_type = ts_internal_to_interval_value(interval, timestamp_type);
493				bucket_function = ts_int16_bucket;
494				break;
495			case INT4OID:
496				interval_in_interval_type = ts_internal_to_interval_value(interval, timestamp_type);
497				bucket_function = ts_int32_bucket;
498				break;
499			case INT8OID:
500				interval_in_interval_type = ts_internal_to_interval_value(interval, timestamp_type);
501				bucket_function = ts_int64_bucket;
502				break;
503			case TIMESTAMPOID:
504				interval_in_interval_type = ts_internal_to_interval_value(interval, INTERVALOID);
505				if (offset.isnull)
506					bucket_function = ts_timestamp_bucket; /* handles also origin */
507				else
508					bucket_function = ts_timestamp_offset_bucket;
509				break;
510			case TIMESTAMPTZOID:
511				interval_in_interval_type = ts_internal_to_interval_value(interval, INTERVALOID);
512				if (offset.isnull)
513					bucket_function = ts_timestamptz_bucket; /* handles also origin */
514				else
515					bucket_function = ts_timestamptz_offset_bucket;
516				break;
517			case DATEOID:
518				interval_in_interval_type = ts_internal_to_interval_value(interval, INTERVALOID);
519				if (offset.isnull)
520					bucket_function = ts_date_bucket; /* handles also origin */
521				else
522					bucket_function = ts_date_offset_bucket;
523				break;
524			default:
525				elog(ERROR, "invalid time_bucket type \"%s\"", format_type_be(timestamp_type));
526		}
527	
528		if (!offset.isnull)
529		{
530			time_bucketed = DirectFunctionCall3(bucket_function,
531												interval_in_interval_type,
532												timestamp_in_time_type,
533												offset.value);
534		}
535		else if (!origin.isnull)
536		{
537			time_bucketed = DirectFunctionCall3(bucket_function,
538												interval_in_interval_type,
539												timestamp_in_time_type,
540												origin.value);
541		}
542		else
543		{
544			time_bucketed =
545				DirectFunctionCall2(bucket_function, interval_in_interval_type, timestamp_in_time_type);
546		}
547	
548		return ts_time_value_to_internal(time_bucketed, timestamp_type);
549	}
