551	TS_FUNCTION_INFO_V1(ts_time_bucket_ng_timestamp);
552	TSDLLEXPORT Datum
553	ts_time_bucket_ng_timestamp(PG_FUNCTION_ARGS)
554	{
555		DateADT ts_date;
556		Interval *interval = PG_GETARG_INTERVAL_P(0);
557		Timestamp timestamp = PG_GETARG_TIMESTAMP(1);
558	
559		if (interval->time != 0)
560		{
561			if (interval->month != 0)
562			{
563				ereport(ERROR,
564						(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
565						 errmsg("interval can't combine months with minutes or hours")));
566			}
567	
568			if (TIMESTAMP_NOT_FINITE(timestamp))
569				PG_RETURN_TIMESTAMP(timestamp);
570	
571			/*
572			 * Handle minutes, hours and days.
573			 */
574			Timestamp origin = (PG_NARGS() > 2 ? PG_GETARG_TIMESTAMP(2) : DEFAULT_ORIGIN);
575			if (TIMESTAMP_NOT_FINITE(origin))
576				PG_RETURN_TIMESTAMP(origin);
577	
578			Timestamp result;
579			int64 period = get_interval_period_timestamp_units(interval);
580			TIME_BUCKET_TS(period, timestamp, result, origin);
581	
582			PG_RETURN_TIMESTAMP(result);
583		}
584	
585		/*
586		 * Discard any time information and work with the date.
587		 */
588		ts_date = DatumGetDateADT(DirectFunctionCall1(timestamp_date, PG_GETARG_DATUM(1)));
589	
590		if (PG_NARGS() > 2)
591		{
592			DateADT result;
593			DateADT origin = DatumGetDateADT(DirectFunctionCall1(timestamp_date, PG_GETARG_DATUM(2)));
594			result = DatumGetDateADT(DirectFunctionCall3(ts_time_bucket_ng_date,
595														 PG_GETARG_DATUM(0),
596														 DateADTGetDatum(ts_date),
597														 DateADTGetDatum(origin)));
598			return DirectFunctionCall1(date_timestamp, DateADTGetDatum(result));
599		}
600		else
601		{
602			DateADT result;
603			result = DatumGetDateADT(DirectFunctionCall2(ts_time_bucket_ng_date,
604														 PG_GETARG_DATUM(0),
605														 DateADTGetDatum(ts_date)));
606			return DirectFunctionCall1(date_timestamp, DateADTGetDatum(result));
607		}
608	}
609	
610	TS_FUNCTION_INFO_V1(ts_time_bucket_ng_timestamptz);
611	TSDLLEXPORT Datum
612	ts_time_bucket_ng_timestamptz(PG_FUNCTION_ARGS)
613	{
614		DateADT result;
615		Datum interval = PG_GETARG_DATUM(0);
616		DateADT ts_date = DatumGetDateADT(DirectFunctionCall1(timestamptz_date, PG_GETARG_DATUM(1)));
617	
618		if (PG_NARGS() > 2)
619		{
620			DateADT origin = DatumGetDateADT(DirectFunctionCall1(timestamptz_date, PG_GETARG_DATUM(2)));
621			result = DatumGetDateADT(DirectFunctionCall3(ts_time_bucket_ng_date,
622														 interval,
623														 DateADTGetDatum(ts_date),
624														 DateADTGetDatum(origin)));
625		}
626		else
627		{
628			result = DatumGetDateADT(
629				DirectFunctionCall2(ts_time_bucket_ng_date, interval, DateADTGetDatum(ts_date)));
630		}
631	
632		return DirectFunctionCall1(date_timestamptz, DateADTGetDatum(result));
633	}
634	
635	TS_FUNCTION_INFO_V1(ts_time_bucket_ng_date);
636	TSDLLEXPORT Datum
637	ts_time_bucket_ng_date(PG_FUNCTION_ARGS)
638	{
639		Interval *interval = PG_GETARG_INTERVAL_P(0);
640		DateADT date = PG_GETARG_DATEADT(1);
641		DateADT origin_date = 0;
642		int origin_year = 2000, origin_month = 1, origin_day = 1;
643		int year, month, day;
644		int delta, bucket_number;
645	
646		if ((interval->time != 0) || ((interval->month != 0) && (interval->day != 0)))
647		{
648			ereport(ERROR,
649					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
650					 errmsg("interval must be either days and weeks, or months and years")));
651		}
652	
653		if ((interval->month == 0) && (interval->day == 0))
654		{
655			ereport(ERROR,
656					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
657					 errmsg("interval must be at least one day")));
658		}
659	
660		if (PG_NARGS() > 2)
661		{
662			origin_date = PG_GETARG_DATUM(2);
663			if (DATE_NOT_FINITE(origin_date))
664				PG_RETURN_DATEADT(origin_date);
665	
666			j2date(origin_date + POSTGRES_EPOCH_JDATE, &origin_year, &origin_month, &origin_day);
667		}
668	
669		if ((origin_day != 1) && (interval->month != 0))
670		{
671			ereport(ERROR,
672					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
673					 errmsg("origin must be the first day of the month"),
674					 errhint("When using timestamptz-version of the function, 'origin' is "
675							 "converted to provided 'timezone'.")));
676		}
677	
678		if (DATE_NOT_FINITE(date))
679			PG_RETURN_DATEADT(date);
680	
681		if (interval->month != 0)
682		{
683			/* Handle months and years */
684	
685			j2date(date + POSTGRES_EPOCH_JDATE, &year, &month, &day);
686			int32 result;
687			int32 offset = (origin_year * 12) + origin_month - 1;
688			int32 timestamp = (year * 12) + month - 1;
689			TIME_BUCKET(interval->month, timestamp, offset, PG_INT32_MIN, PG_INT32_MAX, result);
690	
691			year = result / 12;
692			month = (result % 12) + 1;
693			day = 1;
694	
695			date = date2j(year, month, day) - POSTGRES_EPOCH_JDATE;
696		}
697		else
698		{
699			/* Handle days and weeks */
700	
701			if (date < origin_date)
702			{
703				ereport(ERROR,
704						(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
705						 errmsg("origin must be before the given date")));
706			}
707	
708			delta = date - origin_date;
709			bucket_number = delta / interval->day;
710			date = origin_date + bucket_number * interval->day;
711		}
712	
713		PG_RETURN_DATEADT(date);
714	}
715	
716	TS_FUNCTION_INFO_V1(ts_time_bucket_ng_timezone);
717	TSDLLEXPORT Datum
718	ts_time_bucket_ng_timezone(PG_FUNCTION_ARGS)
719	{
720		Timestamp result;
721		Datum timestamp;
722		Datum interval = PG_GETARG_DATUM(0);
723		Datum timestamptz = PG_GETARG_DATUM(1);
724		Datum tzname = PG_GETARG_DATUM(2);
725	
726		/*
727		 * Convert 'timestamptz' to TIMESTAMP at given 'tzname'.
728		 * The code is equal to 'timestamptz AT TIME ZONE tzname'.
729		 */
730		timestamp = DirectFunctionCall2(timestamptz_zone, tzname, timestamptz);
731	
732		/* Then treat resulting timestamp as a regular one */
733		result =
734			DatumGetTimestamp(DirectFunctionCall2(ts_time_bucket_ng_timestamp, interval, timestamp));
735		if (TIMESTAMP_NOT_FINITE(result))
736			PG_RETURN_TIMESTAMP(result);
737	
738		PG_RETURN_DATUM(DirectFunctionCall2(timestamp_zone, tzname, TimestampGetDatum(result)));
739	}
740	
741	TS_FUNCTION_INFO_V1(ts_time_bucket_ng_timezone_origin);
742	TSDLLEXPORT Datum
743	ts_time_bucket_ng_timezone_origin(PG_FUNCTION_ARGS)
744	{
745		Timestamp result;
746		Datum timestamp, origin;
747		Datum interval = PG_GETARG_DATUM(0);
748		Datum timestamptz = PG_GETARG_DATUM(1);
749		Datum origintz = PG_GETARG_DATUM(2);
750		Datum tzname = PG_GETARG_DATUM(3);
751	
752		/*
753		 * Convert 'origin' to TIMESTAMP at given 'tzname'.
754		 * The code is equal to 'origin AT TIME ZONE tzname'.
755		 */
756		origin = DirectFunctionCall2(timestamptz_zone, tzname, origintz);
757	
758		/* Same for 'timestamptz' */
759		timestamp = DirectFunctionCall2(timestamptz_zone, tzname, timestamptz);
760	
761		/* Then treat resulting 'timestamp' and 'origin' as a regular ones */
762		result = DatumGetTimestamp(
763			DirectFunctionCall3(ts_time_bucket_ng_timestamp, interval, timestamp, origin));
764		if (TIMESTAMP_NOT_FINITE(result))
765			PG_RETURN_TIMESTAMP(result);
766	
767		PG_RETURN_DATUM(DirectFunctionCall2(timestamp_zone, tzname, TimestampGetDatum(result)));
768	}
