681	static bool
682	process_cagg_invalidations_and_refresh(const ContinuousAgg *cagg,
683										   const InternalTimeRange *refresh_window,
684										   const ContinuousAggRefreshContext context, int32 chunk_id,
685										   bool force)
686	{
687		InvalidationStore *invalidations;
688		Oid hyper_relid = ts_hypertable_id_to_relid(cagg->data.mat_hypertable_id, false);
689	
690		/* Lock the continuous aggregate's materialized hypertable to protect against
691		 * concurrent invalidation log processing.
692		 *
693		 * It will produce rows in the `continuous_aggs_materialization_ranges` table
694		 * to be materialized later either serially or in parallel for non-overlap
695		 * refresh ranges.
696		 *
697		 * This is supposed to be a short transaction and in the future we can consider
698		 * relaxing this lock.
699		 */
700		LockRelationOid(hyper_relid, ExclusiveLock);
701		invalidations = invalidation_process_cagg_log(cagg,
702													  refresh_window,
703													  ts_guc_cagg_max_individual_materializations,
704													  context,
705													  force);
706		SPI_commit_and_chain();
707	
708		DEBUG_WAITPOINT("after_process_cagg_invalidations_for_refresh_lock");
709	
710		if (invalidations != NULL)
711		{
712			if (context.callctx == CAGG_REFRESH_CREATION)
713			{
714				Assert(OidIsValid(cagg->relid));
715				ereport(NOTICE,
716						(errmsg("refreshing continuous aggregate \"%s\"", get_rel_name(cagg->relid)),
717						 errhint("Use WITH NO DATA if you do not want to refresh the continuous "
718								 "aggregate on creation.")));
719			}
720	
721			continuous_agg_refresh_with_window(cagg, refresh_window, invalidations, chunk_id, context);
722			if (invalidations)
723				invalidation_store_free(invalidations);
724			return true;
725		}
726	
727		return false;
728	}
729	
730	void
731	continuous_agg_refresh_internal(const ContinuousAgg *cagg,
732									const InternalTimeRange *refresh_window_arg,
733									const ContinuousAggRefreshContext context, const bool start_isnull,
734									const bool end_isnull, bool bucketing_refresh_window, bool force,
735									bool process_hypertable_invalidations, bool extend_last_bucket)
736	{
737		int32 mat_id = cagg->data.mat_hypertable_id;
738		InternalTimeRange refresh_window = *refresh_window_arg;
739		int64 invalidation_threshold;
740		bool nonatomic = ts_process_utility_is_context_nonatomic();
741	
742		/* Reset the saved ProcessUtilityContext value promptly before
743		 * calling Prevent* checks so the potential unsupported (atomic)
744		 * value won't linger there in case of ereport exit.
745		 */
746		ts_process_utility_context_reset();
747	
748		PreventCommandIfReadOnly(REFRESH_FUNCTION_NAME);
749	
750		/* Prevent running refresh if we're in a transaction block since a refresh
751		 * can run two transactions and might take a long time to release locks if
752		 * there's a lot to materialize. Strictly, it is optional to prohibit
753		 * transaction blocks since there will be only one transaction if the
754		 * invalidation threshold needs no update. However, materialization might
755		 * still take a long time and it is probably best for consistency to always
756		 * prevent transaction blocks.  */
757		PreventInTransactionBlock(nonatomic, REFRESH_FUNCTION_NAME);
758	
759		/*
760		 * We don't cagg refresh to fail because of decompression limit. So disable
761		 * the decompression limit for the duration of the refresh.
762		 */
763		const char *old_decompression_limit =
764			GetConfigOption("timescaledb.max_tuples_decompressed_per_dml_transaction", false, false);
765		SetConfigOption("timescaledb.max_tuples_decompressed_per_dml_transaction",
766						"0",
767						PGC_USERSET,
768						PGC_S_SESSION);
769	
770		/* Connect to SPI manager due to the underlying SPI calls */
771		int rc = SPI_connect_ext(SPI_OPT_NONATOMIC);
772		if (rc != SPI_OK_CONNECT)
773			elog(ERROR, "SPI_connect failed: %s", SPI_result_code_string(rc));
774	
775		/* Lock down search_path */
776		int save_nestlevel = NewGUCNestLevel();
777		RestrictSearchPath();
778	
779		/* Like regular materialized views, require owner to refresh. */
780		if (!object_ownercheck(RelationRelationId, cagg->relid, GetUserId()))
781			aclcheck_error(ACLCHECK_NOT_OWNER,
782						   get_relkind_objtype(get_rel_relkind(cagg->relid)),
783						   get_rel_name(cagg->relid));
784	
785		/* No bucketing when open ended */
786		if (bucketing_refresh_window && !(start_isnull && end_isnull))
787		{
788			if (cagg->bucket_function->bucket_fixed_interval == false)
789			{
790				refresh_window = *refresh_window_arg;
791				ts_compute_inscribed_bucketed_refresh_window_variable(&refresh_window.start,
792																	  &refresh_window.end,
793																	  cagg->bucket_function);
794			}
795			else
796			{
797				int64 bucket_width = ts_continuous_agg_fixed_bucket_width(cagg->bucket_function);
798				Assert(bucket_width > 0);
799				refresh_window =
800					compute_inscribed_bucketed_refresh_window(cagg, refresh_window_arg, bucket_width);
801			}
802		}
803	
804		if (refresh_window.start >= refresh_window.end)
805			ereport(ERROR,
806					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
807					 errmsg("refresh window too small"),
808					 errdetail("The refresh window must cover at least one bucket of data."),
809					 errhint("Align the refresh window with the bucket"
810							 " time zone or use at least two buckets.")));
811	
812		/* If there is no other policy defined after this, the inscribed bucket calculated above
813		 * is correct. However, in the case of concurrent policies, if this isn't the last
814		 * policy defined then we should extend the end of the window to include the partial
815		 * bucket. This is done to ensure concurrent policies that are 'adjacent' don't skip a
816		 * bucket We don't need to do this when the CAgg is created WITH DATA, or manually
817		 * refreshed
818		 */
819		if (extend_last_bucket && !(start_isnull && end_isnull))
820		{
821			if (cagg->bucket_function->bucket_fixed_interval == false)
822			{
823				refresh_window.end =
824					ts_compute_beginning_of_the_next_bucket_variable(refresh_window.end,
825																	 cagg->bucket_function);
826			}
827			else
828			{
829				int64 bucket_width = ts_continuous_agg_fixed_bucket_width(cagg->bucket_function);
830				refresh_window.end =
831					ts_time_saturating_add(refresh_window.end, bucket_width - 1, refresh_window.type);
832			}
833		}
834	
835		/*
836		 * Perform the refresh across two transactions.
837		 *
838		 * The first transaction moves the invalidation threshold (if needed) and
839		 * copies over invalidations from the hypertable log to the cagg
840		 * invalidation log. Doing the threshold and copying as part of the first
841		 * transaction ensures that the threshold and new invalidations will be
842		 * visible as soon as possible to concurrent refreshes and that we keep
843		 * locks for only a short period.
844		 *
845		 * The second transaction processes the cagg invalidation log and then
846		 * performs the actual refresh (materialization of data). This transaction
847		 * serializes around a lock on the materialized hypertable for the
848		 * continuous aggregate that gets refreshed.
849		 */
850	
851		/* Set the new invalidation threshold. Note that this only updates the
852		 * threshold if the new value is greater than the old one. Otherwise, the
853		 * existing threshold is returned. */
854		invalidation_threshold = invalidation_threshold_set_or_get(cagg, &refresh_window);
855	
856		/* We must also cap the refresh window at the invalidation threshold. If
857		 * we process invalidations after the threshold, the continuous aggregates
858		 * won't be refreshed when the threshold is moved forward in the
859		 * future. The invalidation threshold should already be aligned on bucket
860		 * boundary. */
861		if (refresh_window.end > invalidation_threshold)
862			refresh_window.end = invalidation_threshold;
863	
864		/* Capping the end might have made the window 0, or negative, so nothing to refresh in that
865		 * case.
866		 *
867		 * For variable width buckets we use a refresh_window.start value that is lower than the
868		 * -infinity value (ts_time_get_nobegin < ts_time_get_min). Therefore, the first check in the
869		 * following if statement is not enough. If the invalidation_threshold returns the min_value for
870		 * the data type, we end up with [nobegin, min_value] which is an invalid time interval.
871		 * Therefore, we have also to check if the invalidation_threshold is defined. If not, no refresh
872		 * is needed.  */
873		if ((refresh_window.start >= refresh_window.end) ||
874			(IS_TIMESTAMP_TYPE(refresh_window.type) &&
875			 invalidation_threshold == ts_time_get_min(refresh_window.type)))
876		{
877			emit_up_to_date_notice(cagg, context);
878	
879			/* Restore search_path */
880			AtEOXact_GUC(false, save_nestlevel);
881	
882			rc = SPI_finish();
883			if (rc != SPI_OK_FINISH)
884				elog(ERROR, "SPI_finish failed: %s", SPI_result_code_string(rc));
885	
886			return;
887		}
888	
889		if (process_hypertable_invalidations)
890		{
891			/*
892			 * If we are using trigger-based invalidations, we can process the
893			 * invalidations for the associated hypertable only and later read the
894			 * invalidations for other hypertables, but when using WAL-based
895			 * invalidation we need to process all of the hypertables that are
896			 * currently using WAL.
897			 *
898			 * We want to prevent any changes to how invalidations are collected
899			 * in the meantime since changing the invalidation collection method
900			 * while this is running might cause problems and miss invalidations.
901			 *
902			 * Concurrency on the replication slot is controlled using some
903			 * special sauce in ReplicationSlotAcquire(), which is called inside
904			 * pg_logical_slot_get_changes_guts().
905			 *
906			 * This will currently generate an error rather than blocking on the
907			 * lock, so we need to add a separate lock to ensure a blocking
908			 * behaviour.
909			 */
910			if (has_invalidation_trigger(
911					ts_hypertable_id_to_relid(cagg->data.raw_hypertable_id, false)))
912				invalidation_process_hypertable_log(cagg->data.raw_hypertable_id, refresh_window.type);
913			else
914				multi_invalidation_process_hypertable_log(get_all_wal_using_hypertables());
915		}
916	
917		/* Commit and Start a new transaction */
918		SPI_commit_and_chain();
919	
920		cagg = ts_continuous_agg_find_by_mat_hypertable_id(mat_id, false);
921	
922		if (!process_cagg_invalidations_and_refresh(cagg,
923													&refresh_window,
924													context,
925													INVALID_CHUNK_ID,
926													force))
927			emit_up_to_date_notice(cagg, context);
928	
929		/* Restore search_path */
930		AtEOXact_GUC(false, save_nestlevel);
931	
932		SetConfigOption("timescaledb.max_tuples_decompressed_per_dml_transaction",
933						old_decompression_limit,
934						PGC_USERSET,
935						PGC_S_SESSION);
936	
937		rc = SPI_finish();
938		if (rc != SPI_OK_FINISH)
939			elog(ERROR, "SPI_finish failed: %s", SPI_result_code_string(rc));
940	}
941	
942	static void
943	debug_refresh_window(const ContinuousAgg *cagg, const InternalTimeRange *refresh_window,
944						 const char *msg)
945	{
946		elog(DEBUG1,
947			 "%s \"%s\" in window [ %s, %s ] internal [ " INT64_FORMAT ", " INT64_FORMAT
948			 " ] minimum [ %s ]",
949			 msg,
950			 NameStr(cagg->data.user_view_name),
951			 ts_internal_to_time_string(refresh_window->start, refresh_window->type),
952			 ts_internal_to_time_string(refresh_window->end, refresh_window->type),
953			 refresh_window->start,
954			 refresh_window->end,
955			 ts_datum_to_string(Int64GetDatum(ts_time_get_min(refresh_window->type)),
956								refresh_window->type));
957	}
958	
959	List *
960	continuous_agg_split_refresh_window(ContinuousAgg *cagg, InternalTimeRange *original_refresh_window,
961										int32 buckets_per_batch, bool refresh_newest_first)
962	{
963		/* Do not produce batches when the number of buckets per batch is zero (disabled) */
964		if (buckets_per_batch == 0)
965		{
966			return NIL;
967		}
968	
969		InternalTimeRange refresh_window = {
970			.type = original_refresh_window->type,
971			.start = original_refresh_window->start,
972			.start_isnull = original_refresh_window->start_isnull,
973			.end = original_refresh_window->end,
974			.end_isnull = original_refresh_window->end_isnull,
975		};
976	
977		debug_refresh_window(cagg, &refresh_window, "begin");
978	
979		const Hypertable *ht = cagg_get_hypertable_or_fail(cagg->data.raw_hypertable_id);
980		const Dimension *time_dim = hyperspace_get_open_dimension(ht->space, 0);
981	
982		/*
983		 * Cap the refresh window to the min and max time of the hypertable
984		 *
985		 * In order to don't produce unnecessary batches we need to check if the start and end of the
986		 * refresh window is NULL then get the min/max slice from the original hypertable
987		 *
988		 */
989		if (refresh_window.start_isnull)
990		{
991			debug_refresh_window(cagg, &refresh_window, "START IS NULL");
992			DimensionSlice *slice = ts_dimension_slice_nth_earliest_slice(time_dim->fd.id, 1);
993	
994			/* If still there's no MIN slice range start then return no batches */
995			if (NULL == slice || TS_TIME_IS_MIN(slice->fd.range_start, refresh_window.type) ||
996				TS_TIME_IS_NOBEGIN(slice->fd.range_start, refresh_window.type))
997			{
998				elog(LOG,
999					 "no min slice range start for continuous aggregate \"%s.%s\", falling back to "
1000					 "single batch processing",
1001					 NameStr(cagg->data.user_view_schema),
1002					 NameStr(cagg->data.user_view_name));
1003				return NIL;
1004			}
1005			refresh_window.start = slice->fd.range_start;
1006			refresh_window.start_isnull = false;
1007		}
1008	
1009		if (refresh_window.end_isnull)
1010		{
1011			debug_refresh_window(cagg, &refresh_window, "END IS NULL");
1012			DimensionSlice *slice = ts_dimension_slice_nth_latest_slice(time_dim->fd.id, 1);
1013	
1014			/* If still there's no MAX slice range start then return no batches */
1015			if (NULL == slice || TS_TIME_IS_MAX(slice->fd.range_end, refresh_window.type) ||
1016				TS_TIME_IS_NOEND(slice->fd.range_end, refresh_window.type))
1017			{
1018				elog(LOG,
1019					 "no min slice range start for continuous aggregate \"%s.%s\", falling back to "
1020					 "single batch processing",
1021					 NameStr(cagg->data.user_view_schema),
1022					 NameStr(cagg->data.user_view_name));
1023				return NIL;
1024			}
1025			refresh_window.end = slice->fd.range_end;
1026			refresh_window.end_isnull = false;
1027		}
1028	
1029		/* Compute the inscribed bucket for the capped refresh window range */
1030		const int64 bucket_width = ts_continuous_agg_bucket_width(cagg->bucket_function);
1031		if (cagg->bucket_function->bucket_fixed_interval == false)
1032		{
1033			ts_compute_inscribed_bucketed_refresh_window_variable(&refresh_window.start,
1034																  &refresh_window.end,
1035																  cagg->bucket_function);
1036		}
1037		else
1038		{
1039			refresh_window =
1040				compute_inscribed_bucketed_refresh_window(cagg, &refresh_window, bucket_width);
1041		}
1042	
1043		/* Check if the refresh size is large enough to produce bathes, if not then return no batches */
1044		const int64 refresh_window_size = i64abs(refresh_window.end - refresh_window.start);
1045		const int64 batch_size = (bucket_width * buckets_per_batch);
1046	
1047		if (refresh_window_size <= batch_size)
1048		{
1049			Oid type = IS_TIMESTAMP_TYPE(refresh_window.type) ? INTERVALOID : refresh_window.type;
1050			Datum refresh_size_interval = ts_internal_to_interval_value(refresh_window_size, type);
1051			Datum batch_size_interval = ts_internal_to_interval_value(batch_size, type);
1052	
1053			elog(LOG,
1054				 "refresh window size (%s) is smaller than or equal to batch size (%s), falling back "
1055				 "to single batch processing",
1056				 ts_datum_to_string(refresh_size_interval, type),
1057				 ts_datum_to_string(batch_size_interval, type));
1058			return NIL;
1059		}
1060	
1061		debug_refresh_window(cagg, &refresh_window, "before produce batches");
1062	
1063		/*
1064		 * Produce the batches to be processed
1065		 *
1066		 * The refresh window is split into multiple batches of size `batch_size` each. The batches are
1067		 * produced in reverse order so that the first range produced is the last range to be processed.
1068		 *
1069		 * The batches are produced in reverse order because the most recent data should be the first to
1070		 * be processed and be visible for the users.
1071		 *
1072		 * It takes in account the invalidation logs (hypertable and materialization hypertable) to
1073		 * avoid producing wholes that have no data to be processed.
1074		 *
1075		 * The logic is something like the following:
1076		 * 1. Get dimension slices from the original hypertables
1077		 * 2. Get either hypertable and materialization hypertable invalidation logs
1078		 * 3. Produce the batches in reverse order
1079		 * 4. Check if the produced batch overlaps either with dimension slices #1 and invalidation logs
1080		 * #2
1081		 * 5. If the batch overlaps with both then it's a valid batch to be processed
1082		 * 6. If the batch overlaps with only one of them then it's not a valid batch to be processed
1083		 * 7. If the batch does not overlap with any of them then it's not a valid batch to be processed
1084		 */
1085		const char *query_str_template = " \
1086			WITH dimension_slices AS ( \
1087				SELECT \
1088					range_start AS start, \
1089					range_end AS end \
1090				FROM \
1091					_timescaledb_catalog.dimension_slice \
1092					JOIN _timescaledb_catalog.dimension ON dimension.id = dimension_slice.dimension_id \
1093				WHERE \
1094					hypertable_id = $1 \
1095					AND dimension_id = $2 \
1096					AND range_end >= range_start \
1097				ORDER BY \
1098					%s \
1099			), \
1100			invalidation_logs AS ( \
1101				SELECT \
1102					lowest_modified_value, \
1103					greatest_modified_value \
1104				FROM \
1105					_timescaledb_catalog.continuous_aggs_materialization_invalidation_log \
1106				WHERE \
1107					materialization_id = $3 \
1108					AND greatest_modified_value >= lowest_modified_value \
1109				UNION ALL \
1110				SELECT \
1111					pg_catalog.min(lowest_modified_value) AS lowest_modified_value, \
1112					pg_catalog.max(greatest_modified_value) AS greatest_modified_value \
1113				FROM \
1114					_timescaledb_catalog.continuous_aggs_hypertable_invalidation_log \
1115				WHERE \
1116					hypertable_id = $1 \
1117					AND greatest_modified_value >= lowest_modified_value \
1118			) \
1119			SELECT \
1120				refresh_start AS start, \
1121				LEAST($6::numeric, refresh_start::numeric + $4::numeric)::bigint AS end \
1122			FROM \
1123				pg_catalog.generate_series($5, $6, $4) AS refresh_start \
1124			WHERE \
1125				EXISTS ( \
1126				    SELECT FROM dimension_slices \
1127					WHERE \
1128						pg_catalog.int8range(refresh_start, LEAST($6::numeric, refresh_start::numeric + $4::numeric)::bigint) \
1129						OPERATOR(pg_catalog.&&) \
1130						pg_catalog.int8range(dimension_slices.start, dimension_slices.end) \
1131				) \
1132				AND EXISTS ( \
1133					SELECT FROM \
1134						invalidation_logs \
1135					WHERE \
1136						pg_catalog.int8range(refresh_start, LEAST($6::numeric, refresh_start::numeric + $4::numeric)::bigint) \
1137						OPERATOR(pg_catalog.&&) \
1138						pg_catalog.int8range(lowest_modified_value, greatest_modified_value) \
1139						AND lowest_modified_value IS NOT NULL \
1140						AND (greatest_modified_value IS NOT NULL AND greatest_modified_value != $7) \
1141				) \
1142			ORDER BY \
1143				refresh_start %s;";
1144	
1145		const char *query_str = psprintf(query_str_template,
1146										 refresh_newest_first ? "range_end DESC" : "range_start ASC",
1147										 refresh_newest_first ? "DESC" : "ASC");
1148	
1149		/* List of InternalTimeRange elements to be returned */
1150		List *refresh_window_list = NIL;
1151	
1152		/* Prepare for SPI call */
1153		int res;
1154		Oid types[] = { INT4OID, INT4OID, INT4OID, INT8OID, INT8OID, INT8OID, INT8OID };
1155		Datum values[] = { Int32GetDatum(ht->fd.id),
1156						   Int32GetDatum(time_dim->fd.id),
1157						   Int32GetDatum(cagg->data.mat_hypertable_id),
1158						   Int64GetDatum(batch_size),
1159						   Int64GetDatum(refresh_window.start),
1160						   Int64GetDatum(refresh_window.end),
1161						   Int64GetDatum(CAGG_INVALIDATION_WRONG_GREATEST_VALUE) };
1162		char nulls[] = { false, false, false, false, false, false, false };
1163		MemoryContext oldcontext = CurrentMemoryContext;
1164	
1165		if (SPI_connect() != SPI_OK_CONNECT)
1166			elog(ERROR, "could not connect to SPI");
1167	
1168		/* Lock down search_path */
1169		int save_nestlevel = NewGUCNestLevel();
1170		RestrictSearchPath();
1171	
1172		res = SPI_execute_with_args(query_str,
1173									7,
1174									types,
1175									values,
1176									nulls,
1177									false /* read_only */,
1178									0 /* count */);
1179	
1180		if (res < 0)
1181			elog(ERROR, "%s: could not produce batches for the policy cagg refresh", __func__);
1182	
1183		if (SPI_processed == 1)
1184		{
1185			elog(LOG,
1186				 "only one batch produced for continuous aggregate \"%s.%s\", falling back to single "
1187				 "batch processing",
1188				 NameStr(cagg->data.user_view_schema),
1189				 NameStr(cagg->data.user_view_name));
1190	
1191			/* Restore search_path */
1192			AtEOXact_GUC(false, save_nestlevel);
1193	
1194			res = SPI_finish();
1195			if (res != SPI_OK_FINISH)
1196				elog(ERROR, "SPI_finish failed: %s", SPI_result_code_string(res));
1197	
1198			return NIL;
1199		}
1200	
1201		/* Build the batches list */
1202		for (uint64 batch = 0; batch < SPI_processed; batch++)
1203		{
1204			bool range_start_isnull, range_end_isnull;
1205			Datum range_start =
1206				SPI_getbinval(SPI_tuptable->vals[batch], SPI_tuptable->tupdesc, 1, &range_start_isnull);
1207			Datum range_end =
1208				SPI_getbinval(SPI_tuptable->vals[batch], SPI_tuptable->tupdesc, 2, &range_end_isnull);
1209	
1210			/* We need to allocate the list in the old memory context because here we're in the SPI
1211			 * context */
1212			MemoryContext saved_context = MemoryContextSwitchTo(oldcontext);
1213			InternalTimeRange *range = palloc0(sizeof(InternalTimeRange));
1214			range->start = DatumGetInt64(range_start);
1215			range->start_isnull = range_start_isnull;
1216			range->end = DatumGetInt64(range_end);
1217			range->end_isnull = range_end_isnull;
1218			range->type = original_refresh_window->type;
1219	
1220			/*
1221			 * To make sure that the first range (or last range in case of refreshing from oldest to
1222			 * newest) is aligned with the end of the refresh window we need to set the end to the
1223			 * maximum value of the time type if the original refresh window end is NULL.
1224			 */
1225			if (((batch == 0 && refresh_newest_first) ||
1226				 (batch == (SPI_processed - 1) && !refresh_newest_first)) &&
1227				original_refresh_window->end_isnull)
1228			{
1229				range->end = ts_time_get_noend_or_max(range->type);
1230				range->end_isnull = true;
1231			}
1232	
1233			/*
1234			 * To make sure that the last range (or first range in case of refreshing from oldest to
1235			 * newest) is aligned with the start of the refresh window we need to set the start to the
1236			 * maximum value of the time type if the original refresh window start is NULL.
1237			 */
1238			if (((batch == (SPI_processed - 1) && refresh_newest_first) ||
1239				 (batch == 0 && !refresh_newest_first)) &&
1240				original_refresh_window->start_isnull)
1241			{
1242				range->start = cagg_get_time_min(cagg);
1243				range->start_isnull = true;
1244			}
1245	
1246			refresh_window_list = lappend(refresh_window_list, range);
1247			MemoryContextSwitchTo(saved_context);
1248	
1249			debug_refresh_window(cagg, range, "batch produced");
1250		}
1251	
1252		/* Restore search_path */
1253		AtEOXact_GUC(false, save_nestlevel);
1254	
1255		res = SPI_finish();
1256		if (res != SPI_OK_FINISH)
1257			elog(ERROR, "SPI_finish failed: %s", SPI_result_code_string(res));
1258	
1259		if (refresh_window_list == NIL)
1260		{
1261			elog(LOG,
1262				 "no valid batches produced for continuous aggregate \"%s.%s\", falling back to single "
1263				 "batch processing",
1264				 NameStr(cagg->data.user_view_schema),
1265				 NameStr(cagg->data.user_view_name));
1266		}
1267	
1268		return refresh_window_list;
1269	}
1270	

