265	static Datum
266	convert_interval_arg(Oid dim_type, Datum interval, Oid *interval_type, const char *str_msg)
267	{
268		Oid convert_to = dim_type;
269		Datum converted;
270	
271		if (IS_TIMESTAMP_TYPE(dim_type))
272			convert_to = INTERVALOID;
273	
274		if (*interval_type != convert_to)
275		{
276			if (!can_coerce_type(1, interval_type, &convert_to, COERCION_IMPLICIT))
277			{
278				if (IS_INTEGER_TYPE(dim_type))
279					ereport(ERROR,
280							(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
281							 errmsg("invalid parameter value for %s", str_msg),
282							 errhint("Use time interval of type %s with the continuous aggregate.",
283									 format_type_be(dim_type))));
284				else if (IS_TIMESTAMP_TYPE(dim_type))
285					ereport(ERROR,
286							(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
287							 errmsg("invalid parameter value for %s", str_msg),
288							 errhint("Use time interval with a continuous aggregate using "
289									 "timestamp-based time "
290									 "bucket.")));
291			}
292		}
293	
294		converted = ts_time_datum_convert_arg(interval, interval_type, convert_to);
295	
296		/* For integer types, first convert all types to int64 to get on a common
297		 * type. Then check valid time ranges against the partition/dimension
298		 * type */
299		switch (*interval_type)
300		{
301			case INT2OID:
302				converted = Int64GetDatum((int64) DatumGetInt16(converted));
303				break;
304			case INT4OID:
305				converted = Int64GetDatum((int64) DatumGetInt32(converted));
306				break;
307			case INT8OID:
308				break;
309			case INTERVALOID:
310				/* For timestamp types, we only support Interval, so nothing further
311				 * to do. */
312				return converted;
313			default:
314				pg_unreachable();
315				break;
316		}
317	
318		/* Cap at min and max */
319		if (DatumGetInt64(converted) < ts_time_get_min(dim_type))
320			converted = ts_time_get_min(dim_type);
321		else if (DatumGetInt64(converted) > ts_time_get_max(dim_type))
322			converted = ts_time_get_max(dim_type);
323	
324		/* Convert to the desired integer type */
325		switch (dim_type)
326		{
327			case INT2OID:
328				converted = Int16GetDatum((int16) DatumGetInt64(converted));
329				break;
330			case INT4OID:
331				converted = Int32GetDatum((int32) DatumGetInt64(converted));
332				break;
333			case INT8OID:
334				/* Already int64, so nothing to do. */
335				break;
336			default:
337				pg_unreachable();
338				break;
339		}
340	
341		*interval_type = dim_type;
342	
343		return converted;
344	}
