346	/*
347	 * Convert an interval to a 128 integer value.
348	 *
349	 * Based on PostgreSQL's interval_cmp_value().
350	 */
351	static inline INT128
352	interval_to_int128(const Interval *interval)
353	{
354		INT128 span;
355		int64 dayfraction;
356		int64 days;
357	
358		/*
359		 * Separate time field into days and dayfraction, then add the month and
360		 * day fields to the days part.  We cannot overflow int64 days here.
361		 */
362		dayfraction = interval->time % USECS_PER_DAY;
363		days = interval->time / USECS_PER_DAY;
364		days += interval->month * INT64CONST(30);
365		days += interval->day;
366	
367		/* Widen dayfraction to 128 bits */
368		span = int64_to_int128(dayfraction);
369	
370		/* Scale up days to microseconds, forming a 128-bit product */
371		int128_add_int64_mul_int64(&span, days, USECS_PER_DAY);
372	
373		return span;
374	}
375	
376	int64
377	interval_to_int64(Datum interval, Oid type)
378	{
379		switch (type)
380		{
381			case INT2OID:
382				return DatumGetInt16(interval);
383			case INT4OID:
384				return DatumGetInt32(interval);
385			case INT8OID:
386				return DatumGetInt64(interval);
387			case INTERVALOID:
388			{
389				const int64 max = ts_time_get_max(TIMESTAMPTZOID);
390				const int64 min = ts_time_get_min(TIMESTAMPTZOID);
391				INT128 bigres = interval_to_int128(DatumGetIntervalP(interval));
392	
393				if (int128_compare(bigres, int64_to_int128(max)) >= 0)
394					return max;
395				else if (int128_compare(bigres, int64_to_int128(min)) <= 0)
396					return min;
397				else
398					return int128_to_int64(bigres);
399			}
400			default:
401				break;
402		}
403	
404		pg_unreachable();
405	
406		return 0;
407	}
