523	/* Ensures the refresh range of the new policy doesn't overlap with an existing one*/
524	PolicyRefreshOffsetOverlapResult
525	policy_refresh_cagg_check_for_overlaps(ContinuousAgg *cagg, Jsonb *policy_config,
526										   int32 existing_job_id)
527	{
528		List *jobs = ts_bgw_job_find_by_proc_and_hypertable_id(POLICY_REFRESH_CAGG_PROC_NAME,
529															   FUNCTIONS_SCHEMA_NAME,
530															   cagg->data.mat_hypertable_id);
531		PolicyRefreshOffsetOverlapResult overlap_result = POLICY_REFRESH_OFFSET_OVERLAP_NONE;
532	
533		if (jobs == NIL)
534			return overlap_result;
535	
536		Hypertable *mat_ht = ts_hypertable_get_by_id(cagg->data.mat_hypertable_id);
537		const Dimension *dim = get_open_dimension_for_hypertable(mat_ht, true);
538	
539		bool start_offset_isnull, end_offset_isnull;
540		int64 start_offset =
541			policy_refresh_cagg_get_refresh_start(cagg, dim, policy_config, &start_offset_isnull);
542		int64 end_offset = policy_refresh_cagg_get_refresh_end(dim, policy_config, &end_offset_isnull);
543	
544		RangeBound lower = {
545			.val = Int64GetDatum(start_offset),
546			.infinite = start_offset_isnull,
547			.inclusive = true,
548			.lower = true,
549		};
550	
551		RangeBound upper = {
552			.val = Int64GetDatum(end_offset),
553			.infinite = end_offset_isnull,
554			.inclusive = false,
555			.lower = false,
556		};
557	
558		TypeCacheEntry *typcache = lookup_type_cache(INT8RANGEOID, TYPECACHE_RANGE_INFO);
559		if (typcache == NULL || typcache->rngelemtype == NULL)
560			elog(ERROR, "cache lookup failed");
561	
562		RangeType *range = make_range_compat(typcache, &lower, &upper, false, NULL);
563	
564		ListCell *lc;
565	
566		elog(DEBUG1,
567			 "start_offset: " INT64_FORMAT ", end_offset: " INT64_FORMAT,
568			 start_offset,
569			 end_offset);
570	
571		/* We need to go through all jobs in order to determine if there is an existing job with the
572		 * exact same offsets */
573		foreach (lc, jobs)
574		{
575			BgwJob *job = (BgwJob *) lfirst(lc);
576	
577			if (existing_job_id == job->fd.id)
578			{
579				continue;
580			}
581	
582			bool start_offset_job_isnull, end_offset_job_isnull;
583			int64 start_offset_job = policy_refresh_cagg_get_refresh_start(cagg,
584																		   dim,
585																		   job->fd.config,
586																		   &start_offset_job_isnull);
587	
588			int64 end_offset_job =
589				policy_refresh_cagg_get_refresh_end(dim, job->fd.config, &end_offset_job_isnull);
590	
591			RangeBound lower_job = {
592				.val = Int64GetDatum(start_offset_job),
593				.infinite = start_offset_job_isnull,
594				.inclusive = true,
595				.lower = true,
596			};
597	
598			RangeBound upper_job = {
599				.val = Int64GetDatum(end_offset_job),
600				.infinite = end_offset_job_isnull,
601				.inclusive = false,
602				.lower = false,
603			};
604	
605			RangeType *range_job = make_range_compat(typcache, &lower_job, &upper_job, false, NULL);
606	
607			elog(DEBUG1,
608				 "start_offset_job: " INT64_FORMAT ", end_offset_job: " INT64_FORMAT,
609				 start_offset_job,
610				 end_offset_job);
611	
612			/* Check if exact same job exists, in which case throw an error or notice depending on
613			 * `if_not_exists` */
614			if (start_offset == start_offset_job && end_offset == end_offset_job)
615			{
616				/* If all arguments are the same, do nothing */
617				return POLICY_REFRESH_OFFSET_OVERLAP_EQUAL;
618			}
619			/* We need to first check all other jobs to see if there is an exact match, since we prefer
620			 * returning an exact match over an overlap, and the list of jobs isn't guaranteed to be
621			 * sorted by start/end offset. */
622			else if (range_overlaps_internal(typcache, range_job, range))
623			{
624				overlap_result = POLICY_REFRESH_OFFSET_OVERLAP;
625			}
626		}
627	
628		return overlap_result;
629	}
