631	Datum
632	policy_refresh_cagg_add_internal(Oid cagg_oid, Oid start_offset_type, NullableDatum start_offset,
633									 Oid end_offset_type, NullableDatum end_offset,
634									 Interval refresh_interval, bool if_not_exists, bool fixed_schedule,
635									 TimestampTz initial_start, const char *timezone,
636									 NullableDatum include_tiered_data, NullableDatum buckets_per_batch,
637									 NullableDatum max_batches_per_execution,
638									 NullableDatum refresh_newest_first)
639	{
640		NameData application_name;
641		NameData proc_name, proc_schema, check_name, check_schema, owner;
642		ContinuousAgg *cagg;
643		CaggPolicyConfig policyconf;
644		int32 job_id;
645		Oid owner_id;
646		JsonbParseState *parse_state = NULL;
647	
648		/* Verify that the owner can create a background worker */
649		owner_id = ts_cagg_permissions_check(cagg_oid, GetUserId());
650		ts_bgw_job_validate_job_owner(owner_id);
651	
652		cagg = ts_continuous_agg_find_by_relid(cagg_oid);
653		if (!cagg)
654			ereport(ERROR,
655					(errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
656					 errmsg("\"%s\" is not a continuous aggregate", get_rel_name(cagg_oid))));
657	
658		if (!start_offset.isnull)
659			start_offset.isnull =
660				ts_if_offset_is_infinity(start_offset.value, start_offset_type, true /* is_start */);
661		if (!end_offset.isnull)
662			end_offset.isnull =
663				ts_if_offset_is_infinity(end_offset.value, end_offset_type, false /* is_start */);
664	
665		parse_cagg_policy_config(cagg,
666								 start_offset_type,
667								 start_offset,
668								 end_offset_type,
669								 end_offset,
670								 &policyconf);
671	
672		/* Insert a new job into jobs table */
673		namestrcpy(&application_name, "Refresh Continuous Aggregate Policy");
674		namestrcpy(&proc_name, POLICY_REFRESH_CAGG_PROC_NAME);
675		namestrcpy(&proc_schema, FUNCTIONS_SCHEMA_NAME);
676		namestrcpy(&check_name, POLICY_REFRESH_CAGG_CHECK_NAME);
677		namestrcpy(&check_schema, FUNCTIONS_SCHEMA_NAME);
678		namestrcpy(&owner, GetUserNameFromId(owner_id, false));
679	
680		pushJsonbValue(&parse_state, WJB_BEGIN_OBJECT, NULL);
681		ts_jsonb_add_int32(parse_state,
682						   POL_REFRESH_CONF_KEY_MAT_HYPERTABLE_ID,
683						   cagg->data.mat_hypertable_id);
684	
685		if (!policyconf.offset_start.isnull)
686			json_add_dim_interval_value(parse_state,
687										POL_REFRESH_CONF_KEY_START_OFFSET,
688										policyconf.offset_start.type,
689										policyconf.offset_start.value);
690		else
691			ts_jsonb_add_null(parse_state, POL_REFRESH_CONF_KEY_START_OFFSET);
692	
693		if (!policyconf.offset_end.isnull)
694			json_add_dim_interval_value(parse_state,
695										POL_REFRESH_CONF_KEY_END_OFFSET,
696										policyconf.offset_end.type,
697										policyconf.offset_end.value);
698		else
699			ts_jsonb_add_null(parse_state, POL_REFRESH_CONF_KEY_END_OFFSET);
700	
701		if (!include_tiered_data.isnull)
702			ts_jsonb_add_bool(parse_state,
703							  POL_REFRESH_CONF_KEY_INCLUDE_TIERED_DATA,
704							  include_tiered_data.value);
705	
706		if (!buckets_per_batch.isnull)
707			ts_jsonb_add_int32(parse_state,
708							   POL_REFRESH_CONF_KEY_BUCKETS_PER_BATCH,
709							   buckets_per_batch.value);
710	
711		if (!max_batches_per_execution.isnull)
712			ts_jsonb_add_int32(parse_state,
713							   POL_REFRESH_CONF_KEY_MAX_BATCHES_PER_EXECUTION,
714							   max_batches_per_execution.value);
715	
716		if (!refresh_newest_first.isnull)
717			ts_jsonb_add_bool(parse_state,
718							  POL_REFRESH_CONF_KEY_REFRESH_NEWEST_FIRST,
719							  refresh_newest_first.value);
720	
721		JsonbValue *result = pushJsonbValue(&parse_state, WJB_END_OBJECT, NULL);
722		Jsonb *config = JsonbValueToJsonb(result);
723	
724		PolicyRefreshOffsetOverlapResult res = policy_refresh_cagg_check_for_overlaps(cagg, config, 0);
725		switch (res)
726		{
727			case POLICY_REFRESH_OFFSET_OVERLAP_NONE:
728				break;
729			case POLICY_REFRESH_OFFSET_OVERLAP_EQUAL:
730				if (if_not_exists)
731				{
732					ereport(NOTICE,
733							(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
734	
735							 errmsg("continuous aggregate refresh policy already exists for "
736									"\"%s\", skipping",
737									get_rel_name(cagg->relid)),
738							 errdetail("A refresh policy with the same start and end offset already "
739									   "exists "
740									   "for "
741									   "continuous aggregate \"%s\".",
742									   get_rel_name(cagg->relid))));
743					PG_RETURN_INT32(-1);
744				}
745				ereport(ERROR,
746						(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
747	
748						 errmsg("continuous aggregate refresh policy already exists for "
749								"\"%s\"",
750								get_rel_name(cagg->relid)),
751						 errdetail("A refresh policy with the same start and end offset already exists "
752								   "for "
753								   "continuous aggregate \"%s\".",
754								   get_rel_name(cagg->relid))));
755				break;
756			case POLICY_REFRESH_OFFSET_OVERLAP:
757				ereport(ERROR,
758						(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
759						 errmsg("refresh interval overlaps with an existing continuous aggregate "
760								"policy on \"%s\"",
761								get_rel_name(cagg->relid))));
762				break;
763		}
764	
765		job_id = ts_bgw_job_insert_relation(&application_name,
766											&refresh_interval,
767											DEFAULT_MAX_RUNTIME,
768											JOB_RETRY_UNLIMITED,
769											&refresh_interval,
770											&proc_schema,
771											&proc_name,
772											&check_schema,
773											&check_name,
774											owner_id,
775											true,
776											fixed_schedule,
777											cagg->data.mat_hypertable_id,
778											config,
779											initial_start,
780											timezone);
781	
782		PG_RETURN_INT32(job_id);
783	}
