785	Datum
786	policy_refresh_cagg_add(PG_FUNCTION_ARGS)
787	{
788		Oid cagg_oid, start_offset_type, end_offset_type;
789		Interval refresh_interval;
790		bool if_not_exists;
791		NullableDatum start_offset, end_offset;
792		NullableDatum include_tiered_data;
793		NullableDatum buckets_per_batch;
794		NullableDatum max_batches_per_execution;
795		NullableDatum refresh_newest_first;
796	
797		ts_feature_flag_check(FEATURE_POLICY);
798	
799		cagg_oid = PG_GETARG_OID(0);
800	
801		if (PG_ARGISNULL(3))
802			ereport(ERROR,
803					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
804					 errmsg("cannot use NULL refresh_schedule_interval")));
805	
806		start_offset_type = get_fn_expr_argtype(fcinfo->flinfo, 1);
807		start_offset.value = PG_GETARG_DATUM(1);
808		start_offset.isnull = PG_ARGISNULL(1);
809		end_offset_type = get_fn_expr_argtype(fcinfo->flinfo, 2);
810		end_offset.value = PG_GETARG_DATUM(2);
811		end_offset.isnull = PG_ARGISNULL(2);
812		refresh_interval = *PG_GETARG_INTERVAL_P(3);
813		if_not_exists = PG_GETARG_BOOL(4);
814		TimestampTz initial_start = PG_ARGISNULL(5) ? DT_NOBEGIN : PG_GETARG_TIMESTAMPTZ(5);
815		bool fixed_schedule = !PG_ARGISNULL(5);
816		text *timezone = PG_ARGISNULL(6) ? NULL : PG_GETARG_TEXT_PP(6);
817		char *valid_timezone = NULL;
818		include_tiered_data.value = PG_GETARG_DATUM(7);
819		include_tiered_data.isnull = PG_ARGISNULL(7);
820		buckets_per_batch.value = PG_GETARG_DATUM(8);
821		buckets_per_batch.isnull = PG_ARGISNULL(8);
822		max_batches_per_execution.value = PG_GETARG_DATUM(9);
823		max_batches_per_execution.isnull = PG_ARGISNULL(9);
824		refresh_newest_first.value = PG_GETARG_DATUM(10);
825		refresh_newest_first.isnull = PG_ARGISNULL(10);
826	
827		Datum retval;
828		/* if users pass in -infinity for initial_start, then use the current_timestamp instead */
829		if (fixed_schedule)
830		{
831			ts_bgw_job_validate_schedule_interval(&refresh_interval);
832			if (TIMESTAMP_NOT_FINITE(initial_start))
833				initial_start = ts_timer_get_current_timestamp();
834		}
835	
836		if (timezone != NULL)
837			valid_timezone = ts_bgw_job_validate_timezone(PG_GETARG_DATUM(6));
838	
839		retval = policy_refresh_cagg_add_internal(cagg_oid,
840												  start_offset_type,
841												  start_offset,
842												  end_offset_type,
843												  end_offset,
844												  refresh_interval,
845												  if_not_exists,
846												  fixed_schedule,
847												  initial_start,
848												  valid_timezone,
849												  include_tiered_data,
850												  buckets_per_batch,
851												  max_batches_per_execution,
852												  refresh_newest_first);
853		if (!TIMESTAMP_NOT_FINITE(initial_start))
854		{
855			int32 job_id = DatumGetInt32(retval);
856			ts_bgw_job_stat_upsert_next_start(job_id, initial_start);
857		}
858		return retval;
859	}
860	
861	Datum
862	policy_refresh_cagg_remove_internal(Oid cagg_oid, bool if_exists)
863	{
864		int32 mat_htid;
865	
866		ContinuousAgg *cagg = ts_continuous_agg_find_by_relid(cagg_oid);
867	
868		if (!cagg)
869			ereport(ERROR,
870					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
871					 errmsg("\"%s\" is not a continuous aggregate", get_rel_name(cagg_oid))));
872	
873		ts_cagg_permissions_check(cagg_oid, GetUserId());
874		mat_htid = cagg->data.mat_hypertable_id;
875		List *jobs = ts_bgw_job_find_by_proc_and_hypertable_id(POLICY_REFRESH_CAGG_PROC_NAME,
876															   FUNCTIONS_SCHEMA_NAME,
877															   mat_htid);
878		if (jobs == NIL)
879		{
880			if (!if_exists)
881				ereport(ERROR,
882						(errcode(ERRCODE_UNDEFINED_OBJECT),
883						 (errmsg("continuous aggregate policy not found for \"%s\"",
884								 get_rel_name(cagg_oid)))));
885			else
886			{
887				ereport(NOTICE,
888						(errmsg("continuous aggregate policy not found for \"%s\", skipping",
889								get_rel_name(cagg_oid))));
890				PG_RETURN_BOOL(false);
891			}
892		}
893	
894		// Delete all bgw jobs associated with this CAgg
895		ListCell *lc;
896		foreach (lc, jobs)
897		{
898			BgwJob *job = (BgwJob *) lfirst(lc);
899			ts_bgw_job_delete_by_id(job->fd.id);
900		}
901	
902		PG_RETURN_BOOL(true);
903	}
904	
905	Datum
906	policy_refresh_cagg_remove(PG_FUNCTION_ARGS)
907	{
908		Oid cagg_oid = PG_GETARG_OID(0);
909		bool if_not_exists = PG_GETARG_BOOL(1); /* Deprecating this argument */
910		bool if_exists;
911	
912		/* For backward compatibility, we use IF_NOT_EXISTS when IF_EXISTS is not given */
913		if_exists = PG_ARGISNULL(2) ? if_not_exists : PG_GETARG_BOOL(2);
914	
915		ts_feature_flag_check(FEATURE_POLICY);
916		(void) policy_refresh_cagg_remove_internal(cagg_oid, if_exists);
917		PG_RETURN_VOID();
918	}
