/* time_bucket extended with timezone support for TIMESTAMPTZOID type.
 * When timezone is specified, the timestamp is first converted to local time
 * using the timezone, then bucketed using the timestamp (not timestamptz) functions,
 * and finally converted back to timestamptz. This matches the behavior of
 * ts_timestamptz_timezone_bucket. */
TSDLLEXPORT int64
ts_time_bucket_by_type_extended_tz(int64 interval, int64 timestamp, Oid timestamp_type,
								   NullableDatum offset, NullableDatum origin, const char *timezone)
{
	/* Defined offset and origin in one function is not supported */
	Assert(offset.isnull == true || origin.isnull == true);

	if (timestamp_type != TIMESTAMPTZOID || timezone == NULL)
	{
		/* No timezone or not timestamptz, use the regular function */
		return ts_time_bucket_by_type_extended(interval, timestamp, timestamp_type, offset, origin);
	}

	/* For timestamptz with timezone, we need to convert through timezone */
	Datum timestamp_datum = ts_internal_to_time_value(timestamp, timestamp_type);
	Datum interval_datum = ts_internal_to_interval_value(interval, INTERVALOID);
	Datum tzname = CStringGetTextDatum(timezone);
	Datum time_bucketed;

	if (!offset.isnull)
	{
		/* Apply offset first */
		timestamp_datum = DirectFunctionCall2(timestamptz_mi_interval,
											  timestamp_datum,
											  offset.value);
	}

	/* Convert to local timestamp according to timezone */
	Datum local_timestamp =
		DirectFunctionCall2(timestamptz_zone, tzname, timestamp_datum);

	if (!origin.isnull)
	{
		/* Convert origin through timezone too */
		Datum local_origin =
			DirectFunctionCall2(timestamptz_zone, tzname, origin.value);
		local_timestamp = DirectFunctionCall3(ts_timestamp_bucket,
											  interval_datum,
											  local_timestamp,
											  local_origin);
	}
	else
	{
		local_timestamp = DirectFunctionCall2(ts_timestamp_bucket,
											  interval_datum,
											  local_timestamp);
	}

	/* Convert back to timestamptz */
	time_bucketed = DirectFunctionCall2(timestamp_zone, tzname, local_timestamp);

	if (!offset.isnull)
	{
		/* Remove offset */
		time_bucketed = DirectFunctionCall2(timestamptz_pl_interval,
											time_bucketed,
											offset.value);
	}

	return ts_time_value_to_internal(time_bucketed, timestamp_type);
}

