330	 * invalidation window was adjusted to be fully inside a refresh window. In the case of a
331	 * continuous aggregate policy or manual refresh, the refresh window is the inscribed bucketed
332	 * window.
333	 *
334	 * The circumscribed behaviour is also used for a refresh on drop, when the refresh is called during
335	 * dropping chunks manually or as part of retention policy.
336	 */
337	InternalTimeRange
338	compute_circumscribed_bucketed_refresh_window(const ContinuousAgg *cagg,
339												  const InternalTimeRange *const refresh_window,
340												  const ContinuousAggBucketFunction *bucket_function)
341	{
342		Assert(cagg != NULL);
343		Assert(cagg->bucket_function != NULL);
344	
345		if (bucket_function->bucket_fixed_interval == false)
346		{
347			InternalTimeRange result = *refresh_window;
348			ts_compute_circumscribed_bucketed_refresh_window_variable(&result.start,
349																	  &result.end,
350																	  bucket_function);
351			return result;
352		}
353	
354		/* Interval is fixed */
355		int64 bucket_width = ts_continuous_agg_fixed_bucket_width(bucket_function);
356		Assert(bucket_width > 0);
357	
358		InternalTimeRange result = *refresh_window;
359		InternalTimeRange largest_bucketed_window =
360			get_largest_bucketed_window(refresh_window->type, bucket_width);
361	
362		/* Get offset and origin for bucket function */
363		NullableDatum offset = INIT_NULL_DATUM;
364		NullableDatum origin = INIT_NULL_DATUM;
365		fill_bucket_offset_origin(cagg, refresh_window, &offset, &origin);
366	
367		/* Defined offset and origin in one function is not supported */
368		Assert(offset.isnull == true || origin.isnull == true);
369	
370		if (refresh_window->start <= largest_bucketed_window.start)
371		{
372			result.start = largest_bucketed_window.start;
373		}
374		else
375		{
376			/* For alignment with a bucket, which includes the start of the refresh window, we just
377			 * need to get start of the bucket. */
378			result.start = ts_time_bucket_by_type_extended(bucket_width,
379														   refresh_window->start,
380														   refresh_window->type,
381														   offset,
382														   origin);
383		}
384	
385		if (refresh_window->end >= largest_bucketed_window.end)
386		{
387			result.end = largest_bucketed_window.end;
388		}
389		else
390		{
391			int64 exclusive_end;
392			int64 bucketed_end;
393	
394			Assert(refresh_window->end > result.start);
395	
396			/* The end of the window is non-inclusive so subtract one before
397			 * bucketing in case we're already at the end of the bucket (we don't
398			 * want to add an extra bucket).  */
399			exclusive_end = ts_time_saturating_sub(refresh_window->end, 1, refresh_window->type);
400			bucketed_end = ts_time_bucket_by_type_extended(bucket_width,
401														   exclusive_end,
402														   refresh_window->type,
403														   offset,
404														   origin);
405	
406			/* We get the time value for the start of the bucket, so need to add
407			 * bucket_width to get the end of it. */
408			result.end = ts_time_saturating_add(bucketed_end, bucket_width, refresh_window->type);
409		}

